export default function createReducer<
  StateT,
  HandleT extends string | number | symbol,
>(
  initialState: StateT,
  handlers: Record<HandleT, (state: StateT, action: any) => StateT>,
) {
  return function reducer<PayloadT extends { type: HandleT }>(
    state: StateT = initialState,
    action: PayloadT,
  ) {
    if (handlers.hasOwnProperty(action.type)) {
      return handlers[action.type](state, action);
    }

    return state;
  };
}

